import re
from datetime import datetime
from typing import Any, Optional
from urllib.parse import quote


def generate_trace_id(source_file: str, source_line: int, data: dict) -> str:
    source_name = source_file.split("/")[-1] if "/" in source_file else source_file
    data_str = str(sorted(data.items())) if data else ""
    hash_input = f"{source_name}:{source_line}:{data_str}"
    hash_val = hashlib.md5(hash_input.encode("utf-8")).hexdigest()[:8]
    timestamp = datetime.now().strftime("%Y%m%d%H%M")
    return f"HV-{timestamp}-{hash_val.upper()}"


def parse_date(value: Any) -> Optional[datetime]:
    if value is None or value == "":
        return None
    if isinstance(value, datetime):
        return value

    date_str = str(value).strip()
    date_formats = [
        "%Y-%m-%d %H:%M:%S",
        "%Y-%m-%d %H:%M",
        "%Y-%m-%d",
        "%Y/%m/%d %H:%M:%S",
        "%Y/%m/%d",
        "%Y年%m月%d日",
        "%Y%m%d",
    ]

    for fmt in date_formats:
        try:
            return datetime.strptime(date_str, fmt)
        except ValueError:
            continue
    return None


def parse_float(value: Any) -> Optional[float]:
    if value is None or value == "":
        return None
    try:
        cleaned = str(value).replace(",", "").replace(" ", "")
        cleaned = re.sub(r"[^\d.-]", "", cleaned)
        return float(cleaned)
    except (ValueError, TypeError):
        return None


def parse_int(value: Any) -> Optional[int]:
    float_val = parse_float(value)
    return int(float_val) if float_val is not None else None


def parse_phone(value: Any) -> Optional[str]:
    if value is None or value == "":
        return None
    phone = re.sub(r"[^\d]", "", str(value))
    if len(phone) == 11 and phone.startswith("1"):
        return phone
    if len(phone) == 8:
        return phone
    return str(value)


def is_in_date_range(date_val: Optional[datetime], start_date: Optional[datetime], end_date: Optional[datetime]) -> bool:
    if date_val is None:
        return True
    if start_date and date_val < start_date:
        return False
    if end_date and date_val > end_date:
        return False
    return True
