import json
import pandas as pd
from pathlib import Path
from typing import List, Dict, Any, Tuple
from .models import FieldMapping
from .utils import parse_date, parse_float, parse_int, parse_phone


class DataReader:
    def __init__(self, field_mappings: List[FieldMapping] = None):
        self.field_mappings = field_mappings or []

    def read_file(self, file_path: str) -> List[Dict[str, Any]]:
        path = Path(file_path)
        if not path.exists():
            raise FileNotFoundError(f"文件不存在: {file_path}")

        suffix = path.suffix.lower()

        if suffix == ".csv":
            return self._read_csv(file_path)
        elif suffix in [".xlsx", ".xls"]:
            return self._read_excel(file_path)
        elif suffix == ".json":
            return self._read_json(file_path)
        else:
            raise ValueError(f"不支持的文件格式: {suffix}")

    def _read_csv(self, file_path: str) -> List[Dict[str, Any]]:
        df = pd.read_csv(file_path, dtype=str, keep_default_na=False)
        records = []
        for idx, row in df.iterrows():
            records.append({
                "_source_line": idx + 2,
                "_source_file": file_path,
                **row.to_dict()
            })
        return records

    def _read_excel(self, file_path: str) -> List[Dict[str, Any]]:
        df = pd.read_excel(file_path, dtype=str, keep_default_na=False)
        records = []
        for idx, row in df.iterrows():
            records.append({
                "_source_line": idx + 2,
                "_source_file": file_path,
                **row.to_dict()
            })
        return records

    def _read_json(self, file_path: str) -> List[Dict[str, Any]]:
        with open(file_path, "r", encoding="utf-8") as f:
            data = json.load(f)

        if isinstance(data, dict):
            data = [data]
        elif not isinstance(data, list):
            raise ValueError("JSON文件格式错误，必须是数组或对象")

        records = []
        for idx, item in enumerate(data):
            records.append({
                "_source_line": idx + 1,
                "_source_file": file_path,
                **item
            })
        return records

    def apply_mapping(self, record: Dict[str, Any]) -> Dict[str, Any]:
        if not self.field_mappings:
            return record

        mapped = {}
        for mapping in self.field_mappings:
            source_val = record.get(mapping.source_field, "")
            if mapping.transform:
                source_val = self._apply_transform(source_val, mapping.transform)
            mapped[mapping.target_field] = source_val

        return mapped

    def _apply_transform(self, value: Any, transform: str) -> Any:
        transforms = {
            "date": lambda v: parse_date(v),
            "float": lambda v: parse_float(v),
            "int": lambda v: parse_int(v),
            "phone": lambda v: parse_phone(v),
            "strip": lambda v: str(v).strip() if v else "",
            "upper": lambda v: str(v).upper() if v else "",
            "lower": lambda v: str(v).lower() if v else "",
        }

        if transform in transforms:
            return transforms[transform](value)
        return value


def load_field_mapping(mapping_file: str) -> List[FieldMapping]:
    path = Path(mapping_file)
    if not path.exists():
        raise FileNotFoundError(f"字段映射文件不存在: {mapping_file}")

    if path.suffix == ".json":
        with open(path, "r", encoding="utf-8") as f:
            mappings_data = json.load(f)
    elif path.suffix in [".csv"]:
        df = pd.read_csv(path)
        mappings_data = df.to_dict("records")
    else:
        raise ValueError(f"不支持的映射文件格式: {path.suffix}")

    return [FieldMapping(**m) for m in mappings_data]
