from typing import List, Dict, Any, Tuple
from datetime import datetime
from .models import HouseRecord, RiskLevel, RecordStatus, ValidationRule
from .utils import parse_date, parse_float, parse_int, parse_phone


class ValidationEngine:
    def __init__(self, custom_rules: List[ValidationRule] = None):
        self.rules = self._get_default_rules()
        if custom_rules:
            self.rules.extend(custom_rules)

    def _get_default_rules(self) -> List[ValidationRule]:
        return [
            ValidationRule(
                name="必填房源编号",
                field="house_id",
                rule_type="required",
                risk_level=RiskLevel.HIGH,
                error_message="房源编号为必填项"
            ),
            ValidationRule(
                name="必填房源标题",
                field="house_title",
                rule_type="required",
                risk_level=RiskLevel.MEDIUM,
                error_message="房源标题为必填项"
            ),
            ValidationRule(
                name="必填价格",
                field="price",
                rule_type="required",
                risk_level=RiskLevel.HIGH,
                error_message="价格为必填项"
            ),
            ValidationRule(
                name="价格范围校验",
                field="price",
                rule_type="range",
                parameters={"min": 1, "max": 100000},
                risk_level=RiskLevel.HIGH,
                error_message="价格应在1-100000万元之间"
            ),
            ValidationRule(
                name="必填面积",
                field="area",
                rule_type="required",
                risk_level=RiskLevel.HIGH,
                error_message="面积为必填项"
            ),
            ValidationRule(
                name="面积范围校验",
                field="area",
                rule_type="range",
                parameters={"min": 5, "max": 2000},
                risk_level=RiskLevel.MEDIUM,
                error_message="面积应在5-2000平方米之间"
            ),
            ValidationRule(
                name="必填位置",
                field="location",
                rule_type="required",
                risk_level=RiskLevel.MEDIUM,
                error_message="位置为必填项"
            ),
            ValidationRule(
                name="室数范围校验",
                field="rooms",
                rule_type="range",
                parameters={"min": 0, "max": 20},
                risk_level=RiskLevel.LOW,
                error_message="室数应在0-20之间"
            ),
            ValidationRule(
                name="厅数范围校验",
                field="halls",
                rule_type="range",
                parameters={"min": 0, "max": 10},
                risk_level=RiskLevel.LOW,
                error_message="厅数应在0-10之间"
            ),
            ValidationRule(
                name="单价异常检测",
                field="price_area_ratio",
                rule_type="ratio_check",
                parameters={"min": 0.1, "max": 50},
                risk_level=RiskLevel.MEDIUM,
                error_message="单价异常，可能存在虚假信息"
            ),
            ValidationRule(
                name="必填中介姓名",
                field="agent_name",
                rule_type="required",
                risk_level=RiskLevel.MEDIUM,
                error_message="中介姓名为必填项"
            ),
            ValidationRule(
                name="中介电话格式校验",
                field="agent_phone",
                rule_type="phone",
                risk_level=RiskLevel.MEDIUM,
                error_message="中介电话格式不正确"
            ),
            ValidationRule(
                name="发布日期有效性",
                field="publish_date",
                rule_type="date_valid",
                risk_level=RiskLevel.LOW,
                error_message="发布日期无效或超出合理范围"
            ),
        ]

    def validate_record(self, record: HouseRecord) -> HouseRecord:
        errors = []
        warnings = []
        risk_scores = {
            RiskLevel.LOW: 0,
            RiskLevel.MEDIUM: 0,
            RiskLevel.HIGH: 0,
            RiskLevel.UNDETERMINED: 0,
        }

        record_dict = record.model_dump()

        for rule in self.rules:
            is_valid, message = self._apply_rule(rule, record_dict)
            if not is_valid:
                if rule.risk_level in [RiskLevel.HIGH, RiskLevel.MEDIUM]:
                    errors.append(f"[{rule.risk_level}] {message}")
                else:
                    warnings.append(f"[{rule.risk_level}] {message}")
                risk_scores[rule.risk_level] += 1

        record.error_messages = errors
        record.warning_messages = warnings

        if errors:
            record.status = RecordStatus.ABNORMAL
        elif warnings and len(warnings) >= 3:
            record.status = RecordStatus.PENDING
        else:
            record.status = RecordStatus.NORMAL

        record.risk_level = self._calculate_risk_level(risk_scores)

        return record

    def _apply_rule(self, rule: ValidationRule, record: Dict[str, Any]) -> Tuple[bool, str]:
        field_value = record.get(rule.field)

        if rule.rule_type == "required":
            if field_value is None or field_value == "" or (isinstance(field_value, str) and field_value.strip() == ""):
                return False, rule.error_message

        elif rule.rule_type == "range":
            if field_value is not None and field_value != "":
                try:
                    val = float(field_value)
                    min_val = rule.parameters.get("min", float("-inf"))
                    max_val = rule.parameters.get("max", float("inf"))
                    if val < min_val or val > max_val:
                        return False, f"{rule.error_message} (当前值: {val})"
                except (ValueError, TypeError):
                    return False, f"{rule.error_message} (无法解析数值)"

        elif rule.rule_type == "phone":
            if field_value:
                phone = re.sub(r"[^\d]", "", str(field_value))
                if not (len(phone) == 11 and phone.startswith("1")) and len(phone) != 8:
                    return False, f"{rule.error_message} (当前值: {field_value})"

        elif rule.rule_type == "date_valid":
            if field_value:
                try:
                    date_val = parse_date(field_value) if not isinstance(field_value, datetime) else field_value
                    if date_val:
                        if date_val.year < 2000 or date_val > datetime.now():
                            return False, f"{rule.error_message} (当前值: {date_val})"
                except:
                    return False, f"{rule.error_message} (无法解析日期)"

        elif rule.rule_type == "ratio_check":
            price = record.get("price")
            area = record.get("area")
            if price and area and float(area) > 0:
                ratio = float(price) / float(area)
                min_ratio = rule.parameters.get("min", 0)
                max_ratio = rule.parameters.get("max", float("inf"))
                if ratio < min_ratio or ratio > max_ratio:
                    return False, f"{rule.error_message} (单价: {ratio:.2f}万元/㎡)"

        return True, ""

    def _calculate_risk_level(self, risk_scores: Dict[RiskLevel, int]) -> RiskLevel:
        if risk_scores[RiskLevel.HIGH] > 0:
            return RiskLevel.HIGH
        elif risk_scores[RiskLevel.MEDIUM] >= 2:
            return RiskLevel.HIGH
        elif risk_scores[RiskLevel.MEDIUM] == 1:
            return RiskLevel.MEDIUM
        elif risk_scores[RiskLevel.LOW] >= 3:
            return RiskLevel.MEDIUM
        elif risk_scores[RiskLevel.LOW] > 0:
            return RiskLevel.LOW
        else:
            return RiskLevel.LOW


class DuplicateChecker:
    def __init__(self):
        self.seen_records = {}

    def check_duplicate(self, record: HouseRecord) -> Tuple[bool, str]:
        key_fields = []

        if record.house_id:
            key_fields.append(f"id:{record.house_id}")

        if record.price and record.area and record.location:
            key_fields.append(f"sig:{record.price}-{record.area}-{record.location}")

        for key in key_fields:
            if key in self.seen_records:
                return True, f"重复记录，与 {self.seen_records[key]} 重复"
            self.seen_records[key] = record.trace_id

        return False, ""
"}

