@click.group()
@click.version_option(__version__, prog_name="house-verification")
def main():
    """房产中介房源验真CLI工具

    用于房产中介房源的数据校验、状态分流和后续闭环处理。
    支持多文件输入、字段映射、日期范围过滤和多格式导出。
    """
    pass


@main.command()
@click.argument("input_files", nargs=-1, type=click.Path(exists=True), required=True)
@click.option("--mapping", "-m", type=click.Path(exists=True), help="字段映射配置文件(JSON/CSV)")
@click.option("--start-date", "-s", help="开始日期 (YYYY-MM-DD)")
@click.option("--end-date", "-e", help="结束日期 (YYYY-MM-DD)")
@click.option("--output", "-o", default="./output", help="输出目录 (默认: ./output)")
@click.option("--format", "-f", "export_format", default="csv", 
              type=click.Choice(["csv", "excel", "json"], case_sensitive=False),
              help="导出格式 (默认: csv)")
@click.option("--quiet", "-q", is_flag=True, help="静默模式，减少输出")
def verify(input_files, mapping, start_date, end_date, output, export_format, quiet):
    """执行房源验真流程

    INPUT_FILES: 一个或多个输入文件路径 (支持CSV/Excel/JSON)
    """
    try:
        if not quiet:
            click.echo("=" * 60)
            click.echo("房产中介房源验真CLI工具")
            click.echo("=" * 60)
            click.echo(f"输入文件: {len(input_files)} 个")
            for f in input_files:
                click.echo(f"  - {Path(f).name}")
            if mapping:
                click.echo(f"字段映射: {Path(mapping).name}")
            if start_date or end_date:
                click.echo(f"日期范围: {start_date or '无'} ~ {end_date or '无'}")
            click.echo(f"导出格式: {export_format.upper()}")
            click.echo(f"输出目录: {output}")
            click.echo("-" * 60)

        pipeline = VerificationPipeline(
            input_files=list(input_files),
            mapping_file=mapping,
            start_date=start_date,
            end_date=end_date,
            output_dir=output,
            export_format=export_format
        )

        with click.progressbar(length=100, label="处理中", show_eta=False) as bar:
            bar.update(20)
            result = pipeline.run()
            bar.update(80)

        if not quiet:
            click.echo()
            click.echo("处理完成!")
            click.echo("-" * 60)
            click.echo(f"总记录数: {result['total_records']}")
            click.echo()
            click.echo("导出文件:")
            for category, file_path in result["exported_files"].items():
                category_name = {
                    "normal": "正常记录",
                    "abnormal": "异常记录",
                    "pending": "待复核记录",
                    "summary": "汇总报告"
                }.get(category, category)
                click.echo(f"  [{category_name}] {file_path}")

        sys.exit(0)

    except FileNotFoundError as e:
        click.echo(f"错误: 文件未找到 - {str(e)}", err=True)
        sys.exit(1)
    except ValueError as e:
        click.echo(f"错误: 参数错误 - {str(e)}", err=True)
        sys.exit(1)
    except RuntimeError as e:
        click.echo(f"错误: 运行时错误 - {str(e)}", err=True)
        sys.exit(1)
    except Exception as e:
        click.echo(f"错误: 未知错误 - {str(e)}", err=True)
        click.echo("请检查输入文件格式和配置是否正确", err=True)
        sys.exit(1)


@main.command(name="list-rules")
